INSERT INTO `indicador_de_logro` (`cod_indicador`, `descrip_indicador`, `cod_materia`, `estado_indicador`) VALUES
	(2, 'Reconoce cada uno de los reinos de la naturaleza.', 18, 'Activo'),
	(3, 'Participa activamente en clase.', 18, 'Activo'),
	(4, 'Reconoce el concepto de naturaleza.', 18, 'Activo'),
	(5, 'Establece la diferencia entre los diferentes tipos de reinos.', 18, 'Activo'),
	(6, 'Se ubica y reconoce los diferentes ecosistemas.', 18, 'Activo'),
	(7, 'Analiza las diferentes teorías propuestas acerca del origen de la vida.', 1, 'Activo'),
	(8, 'Establece claramente las diferencias entre células eucariotas y procariotas.', 1, 'Activo'),
	(9, 'Identifica la célula como unidad funcional, estructural y genética de todo ser vivo.', 1, 'Activo'),
	(10, 'Reconoce las distintas teorías del origen del universo.', 1, 'Activo'),
	(11, 'Establece diferencias entre los tipos de reproducción celular. ', 1, 'Activo'),
	(12, 'Analiza y diferencia los tipos de tejidos animal y vegetal.', 1, 'Activo'),
	(13, 'Reconoce las partes de método científico. ', 1, 'Activo'),
	(14, 'Comprende y explica cada una de las teorías establecidas acerca del origen de la vida en el planeta.', 1, 'Activo'),
	(15, 'Relaciona cada una de las etapas de la evolución del hombre desde los primates hasta el homosapiens.', 1, 'Activo'),
	(16, 'Explica con claridad cada uno de los tipos de respiración y da ejemplos.', 1, 'Activo'),
	(17, 'Comprende la función de cada una de las partes del sistema respiratorio en el hombre.', 1, 'Activo'),
	(18, 'Reconoce las teorías del origen de la vida en el planeta tierra.', 1, 'Activo'),
	(19, 'Reconoce las características de los reinos biológicos. ', 1, 'Activo'),
	(20, 'Entiende la importancia de la microbiología para el hombre.', 1, 'Activo'),
	(21, 'Identifica los diferentes sistemas que conforman un ser vivo.', 1, 'Activo'),
	(22, 'Establece diferencias entre los distintos órganos del cuerpo.', 1, 'Activo'),
	(23, 'Reconoce las funciones de cada uno de los sistemas de los humanos.', 1, 'Activo'),
